solution_code:
#include <iostream>
#include <vector>

int main()
{
    int n;
    std::cin >> n;
    std::vector<int> v;
    for (int i = 0; i < n; ++i)
    {
        int x;
        std::cin >> x;
        v.push_back(x);
    }

    int len { static_cast<int>(v.size()) };
    for (int i = len - 1; i >= 0; --i)
    {
        if (i < len - 1) std::cout << ' ';
        std::cout << v[i];
    }
    std::cout << '\n';
    return 0;
}

