    for (int i = 0; i < n; ++i)
    {
        int x;
        std::cin >> x;
        v.push_back(x);
    }

    // BUG: using size_t causes infinite loop on reverse traversal
    for (std::size_t i = v.size() - 1; i >= 0; --i)
    {
        if (i < v.size() - 1) std::cout << ' ';
        std::cout << v[i];
    }
    std::cout << '\n';
    return 0;
}

